SELECT scl.id, s.name as studentName, scl.remark as changeReason, scl.credit as changeCredit, scl.current_credit as remainingCredit, scl.remark as description, scl.add_time as changeTime FROM student_credit_log scl LEFT JOIN student s ON scl.student_id = s.id
AND s.name LIKE CONCAT(CONCAT('%', #{query.name}), '%')
AND scl.add_time >= #{query.startTime}
AND scl.add_time <= #{query.endTime}
ORDER BY scl.add_time DESC, scl.id DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM student_credit_log scl
LEFT JOIN student s ON scl.student_id = s.id


        AND s.name LIKE CONCAT(CONCAT('%', #{query.name}), '%')


        AND scl.add_time >= #{query.startTime}


        AND scl.add_time  <=  #{query.endTime}
